function fixedNav() {
   const nav = document.querySelector('nav')
   const breakpoint = 1
   if (window.scrollY > breakpoint) {
      nav.classList.add('fixed__nav')
   } else {
      nav.classList.remove('fixed__nav')
   }
}
window.addEventListener('scroll', fixedNav)
